const { execSync } = require('child_process');
const fs = require('fs');

// Recent vault changes (last 48h)
let recentFiles = '';
try {
    recentFiles = execSync(
        `find /mnt/docs/Local-Network-Hub -name "*.md" -mmin -2880 -type f 2>/dev/null | head -20`,
        { encoding: 'utf8' }
    ).trim();
} catch(e) {}

// Open tasks from Claude_Vault
let tasks = '';
try {
    const taskFiles = execSync(
        `find /mnt/docs/Claude_Vault/tasks -name "*.md" -type f 2>/dev/null`,
        { encoding: 'utf8' }
    ).trim().split('\n').filter(Boolean);

    const snippets = taskFiles.slice(0, 15).map(f => {
        try {
            const c = fs.readFileSync(f, 'utf8');
            const title  = (c.match(/^title:\s*(.+)/m) || c.match(/^# (.+)/m) || ['','?'])[1];
            const status = (c.match(/^status:\s*(.+)/m) || ['','?'])[1];
            const prio   = (c.match(/^priority:\s*(.+)/m) || ['',''])[1];
            return `- [${status}${prio ? '/'+prio : ''}] ${title}`.trim();
        } catch { return ''; }
    }).filter(Boolean);
    tasks = snippets.join('\n');
} catch(e) { tasks = 'Could not read tasks.'; }

// Read snippets of recent files
let context = 'No recent changes.';
if (recentFiles) {
    const files = recentFiles.split('\n').filter(Boolean);
    context = files.map(f => {
        try {
            const c = fs.readFileSync(f, 'utf8').substring(0, 400);
            return `### ${f.split('/').pop()}\n${c}`;
        } catch { return ''; }
    }).filter(Boolean).join('\n\n');
}

return [{ json: {
    tasks,
    context,
    date: new Date().toISOString().substring(0, 10)
} }];

const d = $input.first().json;

const prompt = `Today is ${d.date}. You are a concise executive assistant running fully offline.

OPEN TASKS:
${d.tasks || 'None found.'}

RECENT VAULT ACTIVITY:
${d.context}

Write a tight daily briefing (under 200 words):
1. Top 3 priority tasks for today with a one-line reason each
2. Any urgent items or deadlines visible in the notes
3. One suggested focus area

Be direct. No filler. Use markdown.`;

// Model selection: swap to deepseek-r1-7b once registered for better reasoning
const model = 'qwen3:8b';

return [{ json: {
    prompt,
    model,
    payload: JSON.stringify({
        model,
        messages: [{ role: 'user', content: prompt }],
        stream: false,
        options: { temperature: 0.3, num_ctx: 4096 }
    })
} }];

const resp = $input.first().json;
const briefing = resp.choices[0].message.content;

const now = new Date();
const pad = n => String(n).padStart(2,'0');
const ts  = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

const content = `---
type: briefing
date: "${ts}"
generated: "${now.toISOString()}"
source: ollama-local
---

${briefing}
`;

const fs = require('fs');
const outPath = `/mnt/docs/Local-Network-Hub/00-System/daily-briefing-${ts}.md`;
fs.writeFileSync(outPath, content, 'utf8');
fs.writeFileSync('/mnt/docs/Local-Network-Hub/00-System/today.md', content, 'utf8');

return [{ json: { ok: true, file: outPath, preview: briefing.substring(0, 200) } }];
